+        let mut indices = Vec::new();
+        let mut prev: Option<VersionIdx> = None;
+        for seq in 1..=n {
+            let v = make_version(pgno, u64::from(seq), prev);
+            let idx = arena.alloc(v);
+            indices.push(idx);
+            prev = Some(idx);
+        }
+        let head = *indices.last().expect("non-empty chain");
+        (head, indices)
+    }
